--
-- Table structure for table `products`
--

DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `products` (
  `product_id` int(11) NOT NULL AUTO_INCREMENT,
  `sku` varchar(50) DEFAULT NULL,
  `barcode` varchar(100) DEFAULT NULL,
  `name` varchar(255) NOT NULL,
  `generic_name` varchar(150) DEFAULT NULL,
  `brand_name` varchar(150) DEFAULT NULL,
  `dosage_form` varchar(80) DEFAULT NULL,
  `strength` varchar(80) DEFAULT NULL,
  `age_group` enum('all','adult','pediatric') DEFAULT 'all',
  `description` text DEFAULT NULL,
  `type` enum('medicine','general') DEFAULT 'medicine',
  `category` varchar(100) DEFAULT NULL,
  `category_id` int(11) DEFAULT NULL,
  `supplier_id` int(11) DEFAULT NULL,
  `price` decimal(10,2) NOT NULL DEFAULT 0.00,
  `cost_price` decimal(10,2) DEFAULT 0.00,
  `selling_price` decimal(10,2) DEFAULT NULL,
  `stock_quantity` int(11) NOT NULL DEFAULT 0,
  `reorder_level` int(11) DEFAULT 10,
  `pieces_per_box` int(11) DEFAULT 0,
  `price_per_piece` decimal(10,2) DEFAULT 0.00,
  `sell_by_piece` tinyint(1) DEFAULT 0,
  `image_url` varchar(500) DEFAULT NULL,
  `expiring_quantity` int(11) NOT NULL DEFAULT 0,
  `expiry_date` date NOT NULL,
  `location` varchar(255) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE current_timestamp(),
  `current_stage` varchar(50) DEFAULT 'NORMAL',
  `reorder_flag` tinyint(1) DEFAULT 0,
  `urgent_reorder` tinyint(1) DEFAULT 0,
  `emergency_reorder` tinyint(1) DEFAULT 0,
  `sale_price` decimal(10,2) DEFAULT NULL,
  `on_promotion` tinyint(1) DEFAULT 0,
  `rotation_flag` tinyint(1) DEFAULT 0,
  `removal_date` datetime DEFAULT NULL,
  `last_stage_check` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE current_timestamp(),
  `requires_prescription` tinyint(1) NOT NULL DEFAULT 0,
  PRIMARY KEY (`product_id`),
  UNIQUE KEY `sku` (`sku`),
  UNIQUE KEY `barcode` (`barcode`),
  KEY `idx_products_stage` (`current_stage`),
  KEY `idx_products_reorder` (`reorder_flag`,`urgent_reorder`),
  KEY `idx_products_active` (`is_active`),
  KEY `idx_products_expiry` (`expiry_date`),
  KEY `idx_products_stock` (`stock_quantity`),
  KEY `idx_sku` (`sku`),
  KEY `idx_barcode` (`barcode`),
  KEY `idx_category` (`category_id`),
  KEY `idx_supplier` (`supplier_id`),
  KEY `idx_expiry` (`expiry_date`),
  KEY `idx_stock` (`stock_quantity`),
  KEY `idx_products_active_stock` (`is_active`,`stock_quantity`),
  CONSTRAINT `fk_product_category` FOREIGN KEY (`category_id`) REFERENCES `categories` (`category_id`) ON DELETE SET NULL,
  CONSTRAINT `fk_product_supplier` FOREIGN KEY (`supplier_id`) REFERENCES `suppliers` (`supplier_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=397 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

